import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import Button from './ui/Button';
import { Input } from 'postcss';

const BookUpdate = () => {
  const {id} = useParams();
  const [books,setBooks] = useState([]);
  const [bookId,setBookId] = useState("");
  const [bookTitle, setBookTitle] = useState("");
  const [bookDescription, setBookDescription] = useState("");
  const [bookPage, setBookPage] = useState("");

  const bookToUpdate = [
    
  ]


  useEffect(()=>{
    fetch(`http://localhost:3000/api/book/${id}`)
    .then(response=>response.json())
    .then(data=>setBooks(data))
    .catch(error=>console.error('erreur fetching data ', error))

  },[id]);
  return (
    <div>
      <div className="w-[50vh] h-auto">
            <h1 className="text-center text-2xl font-bold mb-4">Ajouter un Livre</h1>
      
            {/* Champ ID */}
            <div className="mb-4">
              <Input
                placeholder="Entrez l'ID du livre"
                value={bookId}
                onChange={(e) => setBookId(e.target.value)}
              />
            </div>
      
            {/* Champ Titre */}
            <div className="mb-4">
              <Input
                placeholder="Entrez le titre du livre"
                value={bookTitle}
                onChange={(e) => setBookTitle(e.target.value)}
              />
            </div>
      
            {/* Champ Description */}
            <div className="mb-4">
              <Input
                placeholder="Entrez la description du livre"
                value={bookDescription}
                onChange={(e) => setBookDescription(e.target.value)}
              />
            </div>
      
            {/* Champ Nombre de Pages */}
            <div className="mb-4">
              <Input
                placeholder="Entrez le nombre de pages"
                type="number"
                value={bookPage}
                onChange={(e) => setBookPage(e.target.value)}
              />
            </div>
      
            {/* Bouton Submit */}
            <Button onClick={handleSubmit}>Submit</Button>
          </div>
    </div>
  );
};

export default BookUpdate;
